import { NextResponse } from 'next/server';
import { grantProAccessAdmin } from '@/lib/firebase/firebase-admin';

export async function POST(request: Request) {
  try {
    const { userId } = await request.json();

    if (!userId) {
      return NextResponse.json({ success: false, error: 'User ID is required.' }, { status: 400 });
    }

    await grantProAccessAdmin(userId);
    return NextResponse.json({ success: true });

  } catch (e: any) {
    console.error(`Failed to upgrade user to pro via API:`, e);
    const message = e.message || 'An unknown error occurred during upgrade.';
    return NextResponse.json({ success: false, error: message }, { status: 500 });
  }
}
